1	<script lang="ts">
2		// DotMeter v2 (the judge's hand-built take, for direct iteration with Jake).
3		// The design thesis: multiply-and-add should be VISIBLE, not narrated.
4		// Every bar is literally its two products stacked; the strip below shows
5		// the arithmetic for whichever candidate you select, live, to two decimals.
6	
7		// The two entries mean something: x is how loud, y is how fast.
8		const CANDIDATES = [
9			{ id: 'c1', name: 'Night Drive', angle: 20 },
10			{ id: 'c2', name: 'Glass Rain', angle: 70 },
11			{ id: 'c3', name: 'Slow Burn', angle: 110 },
12			{ id: 'c4', name: 'Static', angle: 160 }
13		];
14	
15		let challenge = $state<null | 'cheat' | 'short'>(null);
16		let solvedCheat = $state(false);
17		let solvedShort = $state(false);
18		const WHY = {
19			cheat:
20				'A song that is simply louder and faster everywhere piles up score without matching your mix. A raw meter overrates intense tracks, so a recommender built on it keeps pushing whatever is biggest.',
21			short:
22				'A quiet song that matches your mix exactly gets buried under bigger ones. Size is drowning direction, and fixing that is exactly where this lesson is headed.'
23		};
24		function startChallenge(kind: 'cheat' | 'short') {
25			// one click always re-arms: a solved card resets on first click,
26			// whether or not another challenge was active in between
27			if (kind === 'cheat' && (challenge === 'cheat' || solvedCheat)) solvedCheat = false;
28			if (kind === 'short' && (challenge === 'short' || solvedShort)) solvedShort = false;
29			challenge = kind;
30			probeAngle = 40;
31			lengthC1 = 1.0;
32			selected = 'c1';
33		}
34		$effect(() => {
35			if (challenge === 'cheat' && cheatActive) solvedCheat = true;
36			if (challenge === 'short' && shortChanged) solvedShort = true;
37		});
38	
39		let probeAngle = $state(40);
40		let lengthC1 = $state(1.0);
41		let selected = $state('c1');
42		let hovered = $state<string | null>(null);
43		let dragging = $state<'probe' | 'length' | null>(null);
44	
45		const rad = (d: number) => (d * Math.PI) / 180;
46	
47		const probe = $derived({ x: Math.cos(rad(probeAngle)), y: Math.sin(rad(probeAngle)) });
48	
49		const rows = $derived(
50			CANDIDATES.map((c) => {
51				const len = c.id === 'c1' ? lengthC1 : 1;
52				const x = len * Math.cos(rad(c.angle));
53				const y = len * Math.sin(rad(c.angle));
54				const px = probe.x * x; // the x-term product
55				const py = probe.y * y; // the y-term product
56				const score = px + py;
57				// r1 is the score at the SAME one-decimal precision the meter
58				// displays, so leader/tie judgments always match what's on screen.
59				const r1 = Number((Object.is(score, -0) ? 0 : score).toFixed(1));
60				return { ...c, len, x, y, px, py, score, r1 };
61			})
62		);
63	
64		const maxR1 = $derived(Math.max(...rows.map((r) => r.r1)));
65		const leaders = $derived(rows.filter((r) => r.r1 === maxR1).map((r) => r.id));
66		const tied = $derived(leaders.length > 1);
67		const sel = $derived(rows.find((r) => r.id === selected) ?? rows[0]);
68	
69		// The mirror lesson: c1 aims truest but is too short to win.
70		const shortChanged = $derived.by(() => {
71			const c1 = rows[0];
72			if (lengthC1 >= 0.95 || leaders.includes('c1')) return false;
73			return rows.every(
74				(r) =>
75					r.id === 'c1' ||
76					Math.abs(((r.angle - probeAngle + 540) % 360) - 180) >
77						Math.abs(((c1.angle - probeAngle + 540) % 360) - 180)
78			);
79		});
80	
81		// The overtake: c1 stretched AND outscoring a candidate that out-aligns it.
82		// Returns the most deserving victim (best-aligned beaten song) so the flag
83		// can name the exact pair instead of making a vague claim about the board.
84		const cheatVictim = $derived.by(() => {
85			const c1 = rows[0];
86			if (lengthC1 <= 1.05) return null;
87			const dist = (angle: number) => Math.abs(((angle - probeAngle + 540) % 360) - 180);
88			const beaten = rows.filter(
89				(r) => r.id !== 'c1' && dist(r.angle) < dist(c1.angle) && c1.r1 > r.r1
90			);
91			if (beaten.length === 0) return null;
92			return beaten.reduce((a, b) => (dist(a.angle) < dist(b.angle) ? a : b));
93		});
94		const cheatActive = $derived(cheatVictim !== null);
95		const leaderName = $derived(rows.find((r) => r.id === leaders[0])?.name ?? '');
96	
97		// --- Arena geometry (SVG units) ---
98		const S = 400; // viewBox square
99		const CX = S / 2;
100		const CY = S / 2;
101		const R = 92; // unit arrow length in px; 2.0 x R stays inside the frame
102		const pt = (x: number, y: number) => ({ px: CX + x * R, py: CY - y * R });
103	
104		function arrow(x: number, y: number) {
105			const tip = pt(x, y);
106			const ang = Math.atan2(CY - tip.py, tip.px - CX);
107			const L = Math.hypot(tip.px - CX, tip.py - CY);
108			const head = Math.max(7, Math.min(11, L * 0.09));
109			const back = { px: tip.px - head * Math.cos(ang), py: tip.py + head * Math.sin(ang) };
110			const left = {
111				px: back.px - head * 0.55 * Math.sin(ang),
112				py: back.py - head * 0.55 * Math.cos(ang)
113			};
114			const right = {
115				px: back.px + head * 0.55 * Math.sin(ang),
116				py: back.py + head * 0.55 * Math.cos(ang)
117			};
118			return {
119				shaft: { x1: CX, y1: CY, x2: back.px, y2: back.py },
120				head: `${tip.px},${tip.py} ${left.px},${left.py} ${right.px},${right.py}`
121			};
122		}
123	
124		// Tip label placement, in pixel space, not polar: push a touch past the
125		// tip along the arrow's own direction, then sideways, perpendicular to
126		// it. Candidates and the probe pass opposite `side` values, so even when
127		// the probe sweeps exactly onto a candidate's angle the two labels land
128		// on opposite sides of the shared line and never collide.
129		function tipLabel(x: number, y: number, side: 1 | -1) {
130			const tip = pt(x, y);
131			const dx = tip.px - CX;
132			const dy = tip.py - CY;
133			const mag = Math.hypot(dx, dy) || 1;
134			const ux = dx / mag;
135			const uy = dy / mag;
136			const perpx = -uy;
137			const perpy = ux;
138			const px = tip.px + ux * 12 + perpx * 17 * side;
139			const py = tip.py + uy * 12 + perpy * 17 * side;
140			return { px: cl(px), py: Math.min(Math.max(py, 14), S - 8) };
141		}
142	
143		let arenaEl = $state<SVGSVGElement | null>(null);
144		// Measured render width of the arena (viewBox units are S=400, but the
145		// SVG is scaled fluidly by CSS). The two drag handles are invisible hit
146		// circles; size them in real px, not viewBox units, so their on-screen
147		// footprint clears the 44x44 touch-target minimum at every width,
148		// including the narrowest (375px) where the arena shrinks the most.
149		let arenaWidth = $state(400);
150		const scale = $derived(arenaWidth > 0 ? arenaWidth / S : 1);
151		const hitR = $derived(Math.max(12, 24 / scale));
152	
153		function anglesFromEvent(e: PointerEvent) {
154			if (!arenaEl) return null;
155			const r = arenaEl.getBoundingClientRect();
156			const x = ((e.clientX - r.left) / r.width) * S - CX;
157			const y = CY - ((e.clientY - r.top) / r.height) * S;
158			return { angle: ((Math.atan2(y, x) * 180) / Math.PI + 360) % 360, dist: Math.hypot(x, y) / R };
159		}
160	
161		function onArenaPointer(e: PointerEvent) {
162			const a = anglesFromEvent(e);
163			if (!a || !dragging) return;
164			if (dragging === 'probe') probeAngle = Math.round(a.angle / 5) * 5 % 360;
165			else lengthC1 = Math.max(0.5, Math.min(2, Math.round(a.dist * 10) / 10));
166		}
167	
168		function startDrag(kind: 'probe' | 'length', e: PointerEvent) {
169			dragging = kind;
170			(e.currentTarget as Element).setPointerCapture(e.pointerId);
171		}
172	
173		function probeKeys(e: KeyboardEvent) {
174			let h = true;
175			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') probeAngle = (probeAngle + 5) % 360;
176			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') probeAngle = (probeAngle + 355) % 360;
177			else h = false;
178			if (h) e.preventDefault();
179		}
180	
181		function lengthKeys(e: KeyboardEvent) {
182			let h = true;
183			if (e.key === 'ArrowRight' || e.key === 'ArrowUp') lengthC1 = Math.min(2, Math.round((lengthC1 + 0.1) * 10) / 10);
184			else if (e.key === 'ArrowLeft' || e.key === 'ArrowDown') lengthC1 = Math.max(0.5, Math.round((lengthC1 - 0.1) * 10) / 10);
185			else h = false;
186			if (h) e.preventDefault();
187		}
188	
189		const f = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(2);
190		const cl = (v: number) => Math.min(Math.max(v, 24), S - 24);
191		const f1 = (n: number) => (Object.is(n, -0) ? 0 : n).toFixed(1);
192	
193		// Bar scale: scores live in [-2, 2] once c1 can stretch.
194		const BARMAX = 2.05;
195		const barH = 96;
196		const segH = (v: number) => (Math.abs(v) / BARMAX) * (barH / 2);
197	
198		const probeTip = $derived(pt(probe.x, probe.y));
199		const c1row = $derived(rows[0]);
200		const c1HandlePos = $derived(pt(c1row.x, c1row.y));
201	</script>
202	
203	<svelte:window onpointerup={() => (dragging = null)} />
204	
205	<div class="lab" data-interactive="dot-alignment">
206		<p class="invite">
207			Every song here is two numbers: how <em class="qw-loud">loud</em>, how <em class="qw-fast">fast</em>. So is your taste. Turn
208			the amber taste arrow and watch each song's match get <em>built</em>: the <span class="qw-loud">loud product</span> plus
209			the <span class="qw-fast">fast product</span>, stacked into one bar. Then grab Night Drive's round handle and change its size.
210		</p>
211		<div class="challenges">
212			<button class="chal" class:active={challenge === 'cheat' && !solvedCheat} class:done={solvedCheat} onclick={() => startChallenge('cheat')}>
213				<span class="chal-t mono">challenge 01</span>
214				<span class="chal-g">Make a worse match win</span>
215				{#if solvedCheat}
216					<span class="chal-s mono">✓ solved · click to retry</span>
217					<span class="chal-why">{WHY.cheat}</span>
218				{:else if challenge === 'cheat'}
219					<span class="chal-s mono live">in play…</span>
220				{/if}
221			</button>
222			<button class="chal" class:active={challenge === 'short' && !solvedShort} class:done={solvedShort} onclick={() => startChallenge('short')}>
223				<span class="chal-t mono">challenge 02</span>
224				<span class="chal-g">Make the truest song lose</span>
225				{#if solvedShort}
226					<span class="chal-s mono">✓ solved · click to retry</span>
227					<span class="chal-why">{WHY.short}</span>
228				{:else if challenge === 'short'}
229					<span class="chal-s mono live">in play…</span>
230				{/if}
231			</button>
232		</div>
233	
234		<div class="stage">
235			<div class="arena-wrap" bind:clientWidth={arenaWidth}>
236				<svg
237					bind:this={arenaEl}
238					viewBox="0 0 {S} {S}"
239					class="arena"
240					onpointermove={onArenaPointer}
241					role="img"
242					aria-label="An amber probe arrow among four periwinkle candidate arrows; drag the probe tip to turn it, drag c1's tip to stretch it"
243				>
244					<!-- angle ring + ticks -->
245					<circle cx={CX} cy={CY} r={R} class="ring" />
246					{#each Array.from({ length: 12 }, (_, i) => i * 30) as t (t)}
247						<line
248							x1={CX + (R - 4) * Math.cos(rad(t))}
249							y1={CY - (R - 4) * Math.sin(rad(t))}
250							x2={CX + (R + 4) * Math.cos(rad(t))}
251							y2={CY - (R + 4) * Math.sin(rad(t))}
252							class="tick"
253						/>
254					{/each}
255					<!-- axes, whisper-quiet, but named: the two entries ARE qualities -->
256					<line x1={CX - R - 14} y1={CY} x2={CX + R + 14} y2={CY} class="axis" />
257					<line x1={CX} y1={CY - R - 14} x2={CX} y2={CY + R + 14} class="axis" />
258					<text x={CX + R + 18} y={CY - 6} class="axisq q-loud mono" aria-hidden="true">loud</text>
259					<text x={CX - 10} y={CY - R - 8} text-anchor="end" class="axisq q-fast mono" aria-hidden="true">fast</text>
260					<g class="legend" aria-hidden="true">
261						<line x1="16" y1="20" x2="34" y2="20" class="lg probe-stroke" />
262						<text x="40" y="24" class="lgt mono">your taste</text>
263						<line x1="16" y1="38" x2="34" y2="38" class="lg cand-stroke" />
264						<text x="40" y="42" class="lgt mono">songs</text>
265					</g>
266	
267					<!-- coordinates made visible: dashed drops for probe and selected -->
268					{#each [{ x: probe.x, y: probe.y, cls: 'p' }, { x: sel.x, y: sel.y, cls: 'c' }] as d (d.cls)}
269						{@const tip = pt(d.x, d.y)}
270						<line x1={tip.px} y1={tip.py} x2={tip.px} y2={CY} class="drop {d.cls}" />
271						<line x1={tip.px} y1={tip.py} x2={CX} y2={tip.py} class="drop {d.cls}" />
272						<text x={cl(tip.px)} y={CY + (d.cls === 'p' ? 13 : 25)} class="coord mono {d.cls}" aria-hidden="true">{f(d.x)}</text>
273						<text x={CX - (d.cls === 'p' ? 4 : 32)} y={cl(tip.py) - 3} class="coord mono {d.cls}" text-anchor="end" aria-hidden="true">{f(d.y)}</text>
274					{/each}
275	
276					<!-- candidates: each holds still, always named at its own tip -->
277					{#each rows as r (r.id)}
278						{@const a = arrow(r.x, r.y)}
279						{@const lp = tipLabel(r.x, r.y, -1)}
280						<g
281							class="cand"
282							class:sel={selected === r.id}
283							class:hov={hovered === r.id}
284							onpointerdown={() => (selected = r.id)}
285							role="button"
286							tabindex="-1"
287							aria-label={`select ${r.name}`}
288						>
289							<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft cand-stroke" />
290							<polygon points={a.head} class="cand-fill" />
291							<text x={lp.px} y={lp.py} class="lab song-lab halo" aria-hidden="true">{r.name}</text>
292						</g>
293					{/each}
294	
295					<!-- c1 length handle -->
296					<circle
297						cx={c1HandlePos.px}
298						cy={c1HandlePos.py}
299						r={hitR}
300						class="handle length-handle"
301						class:active={dragging === 'length'}
302						class:pulse={challenge !== null && !((challenge === 'cheat' && cheatActive) || (challenge === 'short' && shortChanged))}
303						onpointerdown={(e) => startDrag('length', e)}
304						onkeydown={lengthKeys}
305						role="spinbutton"
306						tabindex="0"
307						data-control="length-c1"
308						aria-label="c1 length"
309						aria-valuemin="0.5"
310						aria-valuemax="2"
311						aria-valuenow={f1(lengthC1)}
312					/>
313	
314					<!-- probe on top: labeled on the object, offset to the opposite
315					     side from any candidate label so a direct sweep-through
316					     never buries either one -->
317					{#if true}
318						{@const a = arrow(probe.x, probe.y)}
319						{@const plab = tipLabel(probe.x, probe.y, 1)}
320						<line {...{ x1: a.shaft.x1, y1: a.shaft.y1, x2: a.shaft.x2, y2: a.shaft.y2 }} class="shaft probe-stroke" />
321						<polygon points={a.head} class="probe-fill" />
322						<text x={plab.px} y={plab.py} class="lab probe-lab halo" aria-hidden="true">your taste</text>
323					{/if}
324					<circle
325						cx={probeTip.px}
326						cy={probeTip.py}
327						r={hitR}
328						class="handle probe-handle"
329						class:active={dragging === 'probe'}
330						onpointerdown={(e) => startDrag('probe', e)}
331						onkeydown={probeKeys}
332						role="slider"
333						tabindex="0"
334						aria-label="probe angle in degrees"
335						aria-valuemin="0"
336						aria-valuemax="360"
337						aria-valuenow={Math.round(probeAngle)}
338					/>
339					<text x="14" y={S - 14} class="angle mono" aria-hidden="true">taste at {Math.round(probeAngle)}°</text>
340				</svg>
341			</div>
342	
343			<div class="meter">
344				{#each rows as r (r.id)}
345					<button
346						class="row"
347						class:leading={leaders.includes(r.id) && !tied}
348						class:sel={selected === r.id}
349						onmouseenter={() => (hovered = r.id)}
350						onmouseleave={() => (hovered = null)}
351						onclick={() => (selected = r.id)}
352						aria-label={`${r.id} score ${f1(r.score)}${leaders.includes(r.id) && !tied ? ', leading' : ''}`}
353					>
354						<span class="row-id">{r.name}</span>
355						<span class="bar" style="--h: {barH}px">
356							<span class="zero"></span>
357							<!-- x-term segment then y-term segment, stacked from the baseline -->
358							<span
359								class="seg segx"
360								class:neg={r.px < 0}
361								style="height: {segH(r.px)}px; bottom: {r.px >= 0 ? barH / 2 : barH / 2 - segH(r.px)}px"
362							></span>
363							<span
364								class="seg segy"
365								class:neg={r.py < 0}
366								style="height: {segH(r.py)}px; bottom: {r.py >= 0
367									? barH / 2 + (r.px > 0 ? segH(r.px) : 0)
368									: barH / 2 - segH(r.py) - (r.px < 0 ? segH(r.px) : 0)}px"
369							></span>
370						</span>
371						<span class="row-score mono">{f1(r.score)}</span>
372						{#if leaders.includes(r.id) && !tied}<span class="leads mono">leads</span>{/if}
373					</button>
374				{/each}
375				{#if tied}<span class="tie mono">tied</span>{/if}
376				{#if cheatVictim}
377					<span class="flag mono">⚑ {cheatVictim.name} matches your taste better, but Night Drive outscores it on size</span>
378				{:else if shortChanged}
379					<span class="flag short mono">⚑ Night Drive matches best, but {leaderName} wins on size</span>
380				{/if}
381			</div>
382		</div>
383		{#if challenge === null && cheatActive}
384			<p class="why">Why this matters: {WHY.cheat}</p>
385		{:else if challenge === null && shortChanged}
386			<p class="why">Why this matters: {WHY.short}</p>
387		{/if}
388		<p class="hint">
389			Click any bar or arrow to inspect it. The dashed lines are that arrow's two
390			entries (its loudness and its speed), the numbers the recipe multiplies.
391		</p>
392	
393		<div class="strip" aria-live="polite">
394			<span class="strip-lead">the whole recipe, live for <b>{sel.name}</b>:</span>
395			<span class="mono eq">
396				<span class="op qw-loud">loud</span>
397				<span class="probe-c">{f(probe.x)}</span>·<span class="cand-c">{f(sel.x)}</span>
398				<span class="op">+</span>
399				<span class="op qw-fast">fast</span>
400				<span class="probe-c">{f(probe.y)}</span>·<span class="cand-c">{f(sel.y)}</span>
401				<span class="op">=</span>
402				<span class="segx-c">{f(sel.px)}</span>
403				<span class="op">+</span>
404				<span class="segy-c">{f(sel.py)}</span>
405				<span class="op">=</span>
406				<span class="score-c">{f1(sel.score)}</span>
407			</span>
408			<span class="strip-note">
409				multiply the matched entries, add the products. The <span class="qw-loud">lilac slice</span>
410				of each bar is its loud product, the <span class="qw-fast">mint slice</span> its fast
411				product; stacked, they are the score.
412			</span>
413		</div>
414	</div>
415	
416	<style>
417		.lab {
418			max-width: 860px;
419			margin: 2rem auto;
420			padding: 1.4rem 1.6rem 1.2rem;
421			background: var(--color-surface);
422			border: 1px solid color-mix(in oklab, var(--color-text) 8%, transparent);
423			border-radius: 14px;
424		}
425		.invite {
426			margin: 0 0 1rem;
427			font-size: 0.98rem;
428			line-height: 1.5;
429			color: color-mix(in oklab, var(--color-text) 88%, transparent);
430		}
431		.invite em { color: var(--color-brand-mint); font-style: normal; }
432		.invite .qw-loud, .lab .invite .qw-loud { color: var(--data-params); font-style: normal; }
433		.invite .qw-fast, .lab .invite .qw-fast { color: color-mix(in oklab, var(--color-brand-mint) 85%, var(--color-text)); font-style: normal; }
434		.mono { font-family: var(--font-mono); }
435	
436		.stage { display: flex; flex-direction: column; gap: 0.8rem; align-items: center; }
437		.arena-wrap { width: 100%; max-width: 620px; }
438		.arena { width: 100%; height: auto; touch-action: none; display: block; }
439	
440		.ring { fill: none; stroke: color-mix(in oklab, var(--color-text) 10%, transparent); stroke-width: 1; }
441		.tick { stroke: color-mix(in oklab, var(--color-text) 14%, transparent); stroke-width: 1; }
442		.axis { stroke: color-mix(in oklab, var(--color-text) 7%, transparent); stroke-width: 1; }
